13→__attribute__((weak))
14→void *
15→_sbrk(ptrdiff_t incr)
16→{
17→  static uintptr_t heap_end;
18→  if (heap_end == 0) heap_end = (uintptr_t) _end;
19→
20→  uintptr_t new_heap_end = heap_end + incr;
21→
22→  register uintptr_t sp asm("sp");
23→  asm("" : "=r" (sp));
24→  if (new_heap_end > sp) { // Check collision with stack pointer
25→    errno = ENOMEM;
26→    return (void*) -1;
27→  }
28→
29→  uintptr_t old_heap_end = heap_end;
30→  heap_end = new_heap_end;
31→  return (void*) old_heap_end;
32→}
