12→__attribute__((weak)) ssize_t
13→_write (int file, const void *ptr, size_t len)
14→{
15→  struct fdentry *fd =__get_fdentry (file);
16→  long data_block[3];
17→  long res;
18→
19→  if (fd == NULL)
20→    return -1;
21→
22→  data_block[0] = fd->handle;
23→  data_block[1] = (long) ptr;
24→  data_block[2] = len;
25→  res = syscall_errno (SEMIHOST_write, data_block);
26→  if (res >= 0)
27→    {
