14→#define SEMIHOST_MODE_R 0
15→#define SEMIHOST_MODE_RPLUS 2
16→#define SEMIHOST_MODE_W 4
17→#define SEMIHOST_MODE_WPLUS 6
18→#define SEMIHOST_MODE_A 8
19→#define SEMIHOST_MODE_APLUS 10
20→
21→/* Open a file.  */
22→__attribute__((weak)) int
23→_open (const char *name, int flags, ...)
24→{
25→  int fh;
26→  int mode;
27→  long data_block[3];
28→
29→  /* Work out mode from flags.  */
30→  if ((flags & (O_RDONLY | O_WRONLY | O_RDWR)) == O_RDONLY)
31→    mode = SEMIHOST_MODE_R;
32→  else if ((flags & (O_WRONLY | O_CREAT | O_TRUNC))
33→	   == (O_WRONLY | O_CREAT | O_TRUNC))
34→    mode = SEMIHOST_MODE_W;
35→  else if ((flags & (O_WRONLY | O_CREAT | O_APPEND))
36→	   == (O_WRONLY | O_CREAT | O_APPEND))
37→    mode = SEMIHOST_MODE_A;
38→  else if ((flags & (O_RDWR | O_CREAT | O_TRUNC))
39→	   == (O_RDWR | O_CREAT | O_TRUNC))
40→    mode = SEMIHOST_MODE_WPLUS;
41→  else if ((flags & (O_RDWR | O_CREAT | O_APPEND))
42→	   == (O_RDWR | O_CREAT | O_APPEND))
43→    mode = SEMIHOST_MODE_APLUS;
44→  else if (flags & O_RDWR)
45→    mode = SEMIHOST_MODE_RPLUS;
46→  else
47→    {
48→      errno = EINVAL;
49→      return -1;
50→    }
51→
52→  data_block[0] = (long) name;
53→  data_block[1] = mode;
54→  data_block[2] = strlen (name);
55→  fh = syscall_errno (SEMIHOST_open, data_block);
56→  /* Failed to open file.  */
57→  if (fh == -1)
58→    return __syscall_error ();
59→
60→  /* Register the file in the fdtable.  */
61→  return __add_fdentry (fh);
62→}
63→
64→int open(const char *name, int flags, ...) {
65→  return _open(name, flags);
66→}
