13→static inline long
14→__semihost_syscall (long id, long *data_block)
15→{
16→  register long a0 asm ("a0") = id;
17→  register long a1 asm ("a1") = (long) data_block;
18→
19→  /* RISC-V semihosting trap sequence.  Must be uncompressed and must not
