#include <string.h>
#include <errno.h>
#include <sys/types.h>

ssize_t _write(int fd, const void* buf, size_t n);

/*
 * putchar() is equivalent to putc(c, stdout)
 * return the character written as an unsigned char cast to an int or
 * EOF on error.
*/

int
putchar(int c)
{
  char cc = (char) c;
  int r = _write (1, &cc, 1);
  if (r == 0)
    errno = EINVAL;

  return c;
}

