#include <alloca.h>
#include <stdarg.h>
#include <stdlib.h>
#include <stdio.h>
#include <unistd.h>
#include "printf_impl.h"

#define VPRINTF_BUFSIZE 64

static char* restrict __vprintf_buf;
static int __vprintf_buf_len;

extern ssize_t _write(int fd, const void* buf, size_t count);

static void __vprintf_help(char c) {
  ++__printf_count;
  __vprintf_buf[__vprintf_buf_len++] = c;
  if (VPRINTF_BUFSIZE == __vprintf_buf_len) {
    _write(1, __vprintf_buf, __vprintf_buf_len);
    __vprintf_buf_len = 0;
  }
}

#if __INTEGER_ONLY
void __printf_impl_lite_wrapped(const char * restrict, va_list, __printf_put);
#define vprintf viprintf
#define __printf_impl __printf_impl_lite_wrapped
__attribute__((weak))
#endif
int vprintf(const char* restrict fmt, va_list args) {
  __vprintf_buf = (char *) alloca (VPRINTF_BUFSIZE);
  __vprintf_buf_len = 0;
  __printf_impl(fmt, args, __vprintf_help);

  _write(1, __vprintf_buf, __vprintf_buf_len);

  return __printf_count;
}

#if !__INTEGER_ONLY
__attribute__((alias("vprintf")))
int viprintf(const char* restrict fmt, va_list args);
#endif

