149→int
150→main(void)
151→{
152→    int    i;
153→    double d;
154→    float  f;
155→#ifdef _TEST_LONG_DOUBLE
156→#ifdef FULL_TESTS
157→    long double ld;
158→#endif
159→#endif
160→    char    *end;
161→    wchar_t *wend;
162→    int      ret = 0;
163→
164→    for (i = 0; i < (int)NTESTS; i++) {
165→        d = strtod(tests[i].string, &end);
166→        if (d != tests[i].dvalue) {
167→            printf("strtod(\"%s\"): got %.17e %a want %.17e %a\n", tests[i].string, d, d,
168→                   tests[i].dvalue, tests[i].dvalue);
169→            ret = 1;
170→        }
171→        if (strcmp(end, tests[i].end_test) != 0) {
172→            printf("strtod(\"%s\") end is \"%s\" expected \"%s\"\n", tests[i].string, end,
173→                   tests[i].end_test);
174→            ret = 1;
175→        }
176→
177→        f = strtof(tests[i].string, &end);
178→        if (f != tests[i].fvalue) {
179→            printf("strtof(\"%s\"): got %.17e %a want %.17e %a\n", tests[i].string, (double)f,
180→                   (double)f, (double)tests[i].fvalue, (double)tests[i].fvalue);
181→            ret = 1;
182→        }
183→        if (strcmp(end, tests[i].end_test) != 0) {
184→            printf("strtof(\"%s\") end is \"%s\" expected \"%s\"\n", tests[i].string, end,
185→                   tests[i].end_test);
186→            ret = 1;
187→        }
188→        if (tests[i].end_test[0] == '%') {
189→            if ((float)d != f) {
190→                printf("strtof(\"%s\") got %a strtod got %a\n", tests[i].string, (double)f, d);
191→                ret = 1;
192→            }
193→        }
194→
195→        mbstowcs(wbuf, tests[i].string, sizeof(wbuf) / sizeof(wchar_t));
196→        mbstowcs(wendbuf, tests[i].end_test, sizeof(wendbuf) / sizeof(wchar_t));
197→
198→        d = wcstod(wbuf, &wend);
199→        if (d != tests[i].dvalue) {
200→            printf("wcstod(\"%ls\"): got %.17e %a want %.17e %a\n", wbuf, d, d, tests[i].dvalue,
201→                   tests[i].dvalue);
202→            ret = 1;
203→        }
204→        if (wcscmp(wend, wendbuf) != 0) {
205→            printf("wcstod(\"%ls\") end is \"%ls\" expected \"%ls\"\n", wbuf, wend, wendbuf);
206→            ret = 1;
207→        }
208→
209→        f = wcstof(wbuf, &wend);
210→        if (f != tests[i].fvalue) {
211→            printf("wcstof(\"%ls\"): got %.17e %a want %.17e %a\n", wbuf, (double)f, (double)f,
212→                   (double)tests[i].fvalue, (double)tests[i].fvalue);
213→            ret = 1;
214→        }
215→        if (wcscmp(wend, wendbuf) != 0) {
216→            printf("wcstof(\"%ls\") end is \"%ls\" expected \"%ls\"\n", wbuf, wend, wendbuf);
217→            ret = 1;
218→        }
219→        if (tests[i].end_test[0] == '%') {
220→            if ((float)d != f) {
221→                printf("wcstof(\"%ls\") got %a wcstod got %a\n", wbuf, (double)f, d);
222→                ret = 1;
223→            }
224→        }
225→
226→#ifdef _TEST_LONG_DOUBLE
227→#ifdef FULL_TESTS
228→        if (sizeof(long double) > sizeof(double) && tests[i].end_test[0] != '%'
229→            && tests[i].end_test[0] != '^') {
230→            ld = strtold(tests[i].string, &end);
231→            if (ld != tests[i].ldvalue) {
232→                printf("strtold(\"%s\"): got %.17Le %La want %.17Le %La\n", tests[i].string, ld, ld,
233→                       tests[i].ldvalue, tests[i].ldvalue);
234→                ret = 1;
235→            }
236→            if (strcmp(end, tests[i].end_test) != 0) {
237→                printf("strtold(\"%s\") end is \"%s\" expected \"%s\"\n", tests[i].string, end,
238→                       tests[i].end_test);
239→                ret = 1;
240→            }
241→
242→            ld = wcstold(wbuf, &wend);
243→            if (ld != tests[i].ldvalue) {
244→                printf("wcstold(\"%ls\"): got %.17Le %La want %.17Le %La\n", wbuf, ld, ld,
245→                       tests[i].ldvalue, tests[i].ldvalue);
246→                ret = 1;
247→            }
248→            if (wcscmp(wend, wendbuf) != 0) {
249→                printf("wcstold(\"%ls\") end is \"%ls\" expected \"%ls\"\n", wbuf, wend, wendbuf);
250→                ret = 1;
251→            }
252→        }
253→#endif
254→#endif
255→    }
256→    return ret;
257→}
