 55→static inline binary32
 56→binary32_from_uint32(uint32_t u32)
 57→{
 58→    union {
 59→        binary32 f32;
 60→        uint32_t u32;
 61→    } u;
 62→
 63→    u.u32 = u32;
 64→    return u.f32;
 65→}
 66→
 67→static inline uint32_t
 68→uint32_from_binary32(binary32 f32)
 69→{
 70→    union {
 71→        binary32 f32;
 72→        uint32_t u32;
 73→    } u;
 74→
 75→    u.f32 = f32;
 76→    return u.u32;
 77→}
