 79→#define UINV_ULP UINTMAX_C(0xffffffff)
 80→
 81→static inline uint32_t
 82→compare_ulp32(binary32 x, binary32 y)
 83→{
 84→    uint32_t ulp = 0;
 85→    uint32_t ux = uint32_from_binary32(x);
 86→    uint32_t uy = uint32_from_binary32(y);
 87→
 88→    if (ux == uy)
 89→        return 0;
 90→
 91→    if (isnan(x) && isnan(y))
 92→        return 0;
 93→    if (isnan(x) || isnan(y))
 94→        return UINV_ULP;
 95→
 96→    if ((ux & 0x80000000UL) != (uy & 0x80000000UL))
 97→        ulp++;
 98→
 99→    ux &= 0x7fffffffUL;
100→    uy &= 0x7fffffffUL;
101→    if (ux > uy)
102→        ulp += ux - uy;
103→    else
104→        ulp += uy - ux;
105→    return ulp;
106→}
