141→        binary64 dy = TEST_FUNC_64(dx);
142→        binary32 fdy = (binary32)dy;
143→
144→        uint32_t ulp = compare_ulp32(fy, fdy);
145→
146→        if (ulp) {
147→            bin = ulp - 1;
148→            if (bin >= ULP_BINS)
149→                bin = ULP_BINS - 1;
150→            ulps[bin]++;
151→        }
152→        if (ulp > max_ulp) {
153→            max_ulp = ulp;
154→            max_ulp_u32 = u32;
155→        }
156→        if (ulp > (uint32_t)check_ulps && check_ulps < MAX_ULP) {
157→            ret = 1;
158→            printf("%s: ulp %" PRIu32 " 0x%08" PRIx32 " %a got 0x%08" PRIx32 " %a want 0x%08" PRIx32
159→                   " %a\n",
