179→                printf(">%d ulp: %8" PRIu32 "\n", bin + 1, ulps[bin]);
180→            else
181→                printf(" %d ulp: %8" PRIu32 "\n", bin + 1, ulps[bin]);
182→        }
183→    }
184→    printf("%s %s: max_ulp %" PRIu32 " at 0x%08" PRIx32 " %a\n", LIBNAME, FNAME, max_ulp,
185→           max_ulp_u32, (binary64)binary32_from_uint32(max_ulp_u32));
186→    if (ret)
187→        printf("FAILED\n");
188→    else
189→        printf("PASSED\n");
