#pragma GCC optimize ("O3")

#include "ref_rredf.h"
#include <math.h>
#define DO_SIN (!(q & 1))
#define NEGATE_SIN ((q & 2))
#define NEGATE_COS ((q & 2))
#define TRIVIAL_RESULT(x) FLOAT_CHECKDENORM(x)
#define ERR_INF MATHERR_SINF_INF

#if 1
//static const
float cst_libm_sincosf[] =
{
    //For sinf polynomial:
    -1.666665066929417292436220415142244613956015227491999719404711781344783392564922e-01f,     //SIN_C1
    8.331978663157089651408875887703995477889496917296385733254577121461421466427772e-03f,      //SIN_C2
    -1.949563623766929906511886482584265500187314705496861877317774185883215997931494e-04f,     //SIN_C3

    //For cosf polynomial:
    1.0f,  //COS_C1
    -4.999989478137016757327030935768632852012781143541026304540837816323349768666875e-01f,     //COS_C2
    4.165629457842617238353362092016541041535652603456375154392942188742496860024377e-02f,      //COS_C3
    -1.35978231111049428748566568960423202948250988565693107969571193763372093404347e-03f       //COS_C4
};

    #define CST_LIBM_SIN_C1     (cst_libm_sincosf[0])
    #define CST_LIBM_SIN_C2     (cst_libm_sincosf[1])
    #define CST_LIBM_SIN_C3     (cst_libm_sincosf[2])
    #define CST_LIBM_COS_C1     (cst_libm_sincosf[3])
    #define CST_LIBM_COS_C2     (cst_libm_sincosf[4])
    #define CST_LIBM_COS_C3     (cst_libm_sincosf[5])
    #define CST_LIBM_COS_C4     (cst_libm_sincosf[6])
#else
    #define CST_LIBM_SIN_C1     (-1.666665066929417292436220415142244613956015227491999719404711781344783392564922e-01f)
    #define CST_LIBM_SIN_C2     (8.331978663157089651408875887703995477889496917296385733254577121461421466427772e-03f)
    #define CST_LIBM_SIN_C3     (-1.949563623766929906511886482584265500187314705496861877317774185883215997931494e-04f)
    #define CST_LIBM_COS_C1     (1.0f)
    #define CST_LIBM_COS_C2     (-4.999989478137016757327030935768632852012781143541026304540837816323349768666875e-01f)
    #define CST_LIBM_COS_C3     (4.165629457842617238353362092016541041535652603456375154392942188742496860024377e-02f)
    #define CST_LIBM_COS_C4     (-1.35978231111049428748566568960423202948250988565693107969571193763372093404347e-03f)
#endif

#ifdef __STDC__
	float sinf(float x)
#else
	float sinf(x)
	float x;
#endif
{
    int q;
    x = ref__mathlib_rredf(x, &q);

    if (__builtin_expect(q < 0, 0)) { // this signals tiny, inf, or NaN
        unsigned k = fai(x) << 1;
        if (k < 0xFF000000)            // tiny
            return TRIVIAL_RESULT(x);
        else if (k == 0xFF000000)      // inf
            return ERR_INF(x);
        else                           // NaN
            return FLOAT_INFNAN(x);
    }

    if (DO_SIN) {
        float x2 = x*x;

        x += x * (x2 * (CST_LIBM_SIN_C1 + x2 * (CST_LIBM_SIN_C2 + x2 * (CST_LIBM_SIN_C3))));
        if (NEGATE_SIN)
            x = -x;
        return x;
    } else {
        float x2 = x*x;
        x = CST_LIBM_COS_C1 + x2 * (CST_LIBM_COS_C2 + x2 * (CST_LIBM_COS_C3 + x2 * (CST_LIBM_COS_C4)));
        if (NEGATE_COS)
            x = -x;
        return x;
    }
}
#pragma GCC reset_options

#ifdef _DOUBLE_IS_32BITS

#ifdef __STDC__
	double sin(double x)
#else
	double sin(x)
	double x;
#endif
{
	return (double) sinf((float) x);
}

#endif /* defined(_DOUBLE_IS_32BITS) */
